"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[492],{460:e=>{e.exports=JSON.parse('{"functions":[{"name":"cast","desc":"Fires a projectile. Resolves `options.type` against the definitions module,\\nthen dispatches to the least-loaded simulation actor in the pool.\\n\\nOn the server, `timestamp` should reflect the moment from the shooter\'s\\nperspective \u2014 typically `clientTimestamp - playerPing - interpolation`.\\nOn the client, `workspace:GetServerTimeNow()` is fine \u2014 the client World\\nhas no rollback path.","params":[{"name":"options","desc":"","lua_type":"CastOptions"}],"returns":[],"function_type":"method","source":{"line":472,"path":"src/World.lua"}},{"name":"hitscan","desc":"Resolves a single-frame ray. Server-side, queries the rollback store for\\nlag-compensated character hits using `options.timestamp`; the projectile\\nloop is bypassed entirely. Client-side, only world geometry is tested \u2014\\nthe client World has no rollback path, so `onIntersection` will not fire.\\n\\nReuses the same [`ProjectileDefinition`](Hindsight#ProjectileDefinition) as\\n[`cast`](#cast). Hitscan-relevant fields: `range`, `power`, `angle`, `loss`,\\n`collaterals`, `raycastFilter`, `filter`, `onImpact`, `onIntersection`.\\nProjectile-only fields (`velocity`, `gravity`, `lifetime`) are ignored.\\n\\n`onDestroyed` is **not** fired by the hitscan path \u2014 the terminal callback\\nis the last `onImpact` or `onIntersection`. Out-of-range scans fire no\\ncallback at all.\\n\\nPenetration and ricochet behave identically to the projectile path,\\nbounded by `MAX_ITERATIONS` (16) to prevent runaway bounces.","params":[{"name":"options","desc":"","lua_type":"CastOptions"}],"returns":[],"function_type":"method","source":{"line":498,"path":"src/World.lua"}},{"name":"destroy","desc":"Tears down the simulation actor pool. Disconnects every Output binding,\\ndestroys every Actor, and clears internal references. After `destroy`, the\\nWorld is unusable \u2014 build a new one with [`Hindsight.createWorld`](Hindsight#createWorld).","params":[],"returns":[],"function_type":"method","source":{"line":516,"path":"src/World.lua"}}],"properties":[{"name":"rollback","desc":"The rollback store. See the [`Rollback`](Rollback) class for the full\\nmethod list.","lua_type":"Rollback","source":{"line":63,"path":"src/World.lua"}}],"types":[],"name":"World","desc":"A simulation world. Owns the actor pool, the snapshot store, and the\\nprojectile definitions registry. Built by [`Hindsight.createWorld`](Hindsight#createWorld).\\n\\nA typical server uses one World; clients use one World per peer for\\nvisuals only. Server and client Worlds do not share state \u2014 both speak the\\nsame definitions module independently because each Actor `require`s the\\nmodule in its own VM.","source":{"line":35,"path":"src/World.lua"}}')}}]);